function solve(edges, online, k) {
    const n = online.length;
    const adj = new Array(n).fill().map(() => []);
    const in_degree = new Array(n).fill(0);
    for (const [u, v, c] of edges) {
        adj[u].push([v, c]);
        in_degree[v]++;
    }

    const queue = [];
    for (let i = 0; i < n; i++) {
        if (in_degree[i] === 0) {
            queue.push(i);
        }
    }

    const top_order = [];
    while (queue.length > 0) {
        const u = queue.shift();
        top_order.push(u);
        for (const [v, c] of adj[u]) {
            in_degree[v]--;
            if (in_degree[v] === 0) {
                queue.push(v);
            }
        }
    }

    const max_min = new Array(n).fill(-Infinity);
    const total_cost = new Array(n).fill(Infinity);
    max_min[0] = Infinity;
    total_cost[0] = 0;

    for (const u of top_order) {
        if (!online[u]) continue;
        for (const [v, c] of adj[u]) {
            if (!online[v]) continue;
            const new_min = Math.min(max_min[u], c);
            const new_total = total_cost[u] + c;
            if (new_total > k) continue;
            if (new_min > max_min[v]) {
                max_min[v] = new_min;
                total_cost[v] = new_total;
            } else if (new_min === max_min[v]) {
                if (new_total < total_cost[v]) {
                    total_cost[v] = new_total;
                }
            }
        }
    }

    return max_min[n - 1] === -Infinity ? -1 : max_min[n - 1];
}
